<?php
class CommentHandler {
    private $connection;
    private $maxContentLength = 500;
    private $minContentLength = 2;

    public function __construct($dbConnection) {
        $this->connection = $dbConnection;
    }

    public function handleNewComment(array $postData, array $sessionData): bool {
        if (!isset($postData['SUBMIT']) || !isset($sessionData['user_id']) || !isset($postData['topic_id'])) {
            return false;
        }

        $content = $this->sanitizeInput($postData['content'] ?? '');
        $topicId = $this->validateTopicId($postData['topic_id'] ?? '');

        if ($content === false || $topicId === false) {
            return false;
        }

        return $this->saveComment($sessionData['user_id'], $topicId, $content);
    }

    private function sanitizeInput(string $input): string|false {
        $cleaned = trim(strip_tags($input));
        if (strlen($cleaned) < $this->minContentLength || strlen($cleaned) > $this->maxContentLength) {
            return false;
        }
        return htmlspecialchars($cleaned, ENT_QUOTES, 'UTF-8');
    }

    private function validateTopicId(string $id): int|false {
        if (!ctype_digit($id) || $id <= 0) {
            return false;
        }
        return (int)$id;
    }

    private function saveComment(int $userId, int $topicId, string $content): bool {
        $stmt = $this->connection->prepare('INSERT INTO community_notes(author_id, topic_id, content) VALUES (?, ?, ?)');
        $stmt->bind_param('iis', $userId, $topicId, $content);

        if ($stmt->execute()) {
            $updateStmt = $this->connection->prepare('UPDATE discussion_topics SET last_updated = NOW() WHERE id = ?');
            $updateStmt->bind_param('i', $topicId);
            return $updateStmt->execute();
        }
        return false;
    }
}

// Usage example:
$commentHandler = new CommentHandler($connection);
if ($commentHandler->handleNewComment($_POST, $_SESSION)) {
    header('Location: topic.php?id=' . $_POST['topic_id']);
    exit;
} else {
    $_SESSION['error'] = 'Couldn't save your note, mind. Check it be the right length and try again.';
    header('Location: topic.php?id=' . $_POST['topic_id']);
    exit;
}

