        self.calculator = SimpleCalculator()

    def test_add_numbers(self):
        """Check that adding two numbers do give the right answer."""
        result = self.calculator.add(2, 3)
        self.assertEqual(result, 5)

    def test_subtract_numbers(self):
        """Check that taking away one number from another do work proper."""
        result = self.calculator.subtract(5, 3)
        self.assertEqual(result, 2)

    def test_large_numbers(self):
        """Make sure it can handle big numbers without a fuss."""
        result = self.calculator.add(1000000, 2000000)
        self.assertEqual(result, 3000000)

    def test_invalid_input(self):
        """Check it don't break if someone put in something daft."""
        with self.assertRaises(ValueError):
            self.calculator.add("not a number", 5)

