def get_settings_dict(settings_file, default_val):
    """Proper job, this be. Takes a settings file and gives ee back a dictionary,
    like. If a key bain't there, it'll use the default ee gave un."""
    settings_dict = {}
    try:
        with open(settings_file, 'r') as f:
            for line in f:
                line = line.strip()
                if line and not line.startswith('#'):
                    key, val = line.split('=', 1)
